import{_ as a,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"56. Uniform Laundry Allowance","description":"","frontmatter":{"title":"56. Uniform Laundry Allowance","eba":"Doctors in Training 2022-2026","topics":["allowances","uniforms"]},"headers":[],"relativePath":"ebas/doctors-in-training/allowances/56-uniform-laundry-allowance.md","filePath":"ebas/doctors-in-training/allowances/56-uniform-laundry-allowance.md"}'),t={name:"ebas/doctors-in-training/allowances/56-uniform-laundry-allowance.md"};function s(i,e,l,c,u,d){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_56-uniform-laundry-allowance" tabindex="-1">56. Uniform Laundry Allowance <a class="header-anchor" href="#_56-uniform-laundry-allowance" aria-label="Permalink to &quot;56. Uniform Laundry Allowance&quot;">​</a></h1><p><strong>56.1</strong> A Doctor must either:</p><p><strong>(a)</strong> be supplied with sufficient suitable and serviceable uniforms that must be laundered at the expense of the Health Service; or</p><p><strong>(b)</strong> be paid a Uniforms and Laundry Allowance pursuant to <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 2.3. The Health Service must either launder or pay for the laundering of such uniform.</p><p><strong>56.2</strong> The Health Service may deem scrubs or similar to constitute a uniform for the purposes of this clause 56.</p><p><strong>56.3</strong> Uniforms supplied pursuant to subclause 56.1(a) above remain the property of the Health Service concerned and must be returned at the completion of the Doctor&#39;s period of service at that Health Service.</p><p><strong>56.4</strong> The Uniforms and Laundry Allowance described in subclause 56.1(b) above must be paid during all absences on leave, except absence on long service leave and absence on personal leave beyond 21 days.</p><p>Plain language terms: uniform allowance, laundry allowance.</p>',8)])])}const f=a(t,[["render",s]]);export{m as __pageData,f as default};
